    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (!visited[i][j] && grid[i][j] !== 0) {
                const sum = dfs(i, j);
                if (sum % k === 0) {
                    count++;
                }
            }
        }
    }

    return count;
}

